namespace sv_e4f1b5c2c0654431a1addd3fa7846e58.Services;

/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies all subscribers when it changes.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_e4f1b5c2c0654431a1addd3fa7846e58.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts on a 10-second interval.
/// Polling only runs while at least one subscriber has called <see cref="StartPolling"/>.
/// All subscribers are notified via <see cref="OnAlertCountChanged"/> when new data arrives.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _pollingSubscribers;

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query returning low-stock item count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begin polling. Multiple callers may start polling; the timer runs as long as
    /// at least one subscriber is active.
    /// </summary>
    public void StartPolling()
    {
        _pollingSubscribers++;
        if (_pollingSubscribers == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Stop polling for this subscriber. The timer is disposed when the last subscriber leaves.
    /// </summary>
    public void StopPolling()
    {
        _pollingSubscribers = Math.Max(0, _pollingSubscribers - 1);
        if (_pollingSubscribers == 0)
        {
            CancelTimer();
        }
    }

    /// <summary>Fetch once and notify all subscribers immediately.</summary>
    public async Task RefreshAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire an immediate first poll so the UI isn't blank until the first tick.
        await RefreshAsync();

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException) { /* expected on dispose / stop */ }
    }

    private async void OnWarehouseChanged()
    {
        if (_pollingSubscribers > 0)
        {
            await RefreshAsync();
        }
    }

    private void CancelTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        CancelTimer();
    }
}

