+    {
+        // Fire an immediate first poll so the UI isn't blank until the first tick.
+        await RefreshAsync();
+
+        try
+        {
+            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
+            {
+                await RefreshAsync();
+            }
+        }
